
import '../css/Blog.css';
import React, {useEffect} from 'react';
import { makeStyles, withTheme } from '@material-ui/core/styles';
import Typography from '@material-ui/core/Typography';
import Grid from '@material-ui/core/Grid';
import headerPic from '../assets/blog_header.jpg';
import Axios from "axios";
import {Post} from "./Post";
import CircularProgress from '@material-ui/core/CircularProgress';

const useStyles = makeStyles((theme) => ({
    root: {
    },
    overlay: {
        zIndex: 1,
        position: 'absolute',
        top: '0',
        bottom: '5vh',
        left: 0,
        right: 0,
    },
    blog: {
        zIndex: 2,
        position: 'absolute',
        backgroundColor: 'transparent',
        top: '0',
        bottom: '0',
        marginTop: '20vh',
        overflowX: 'hidden',
        overflowY: 'scroll',
        left: 0,
        right: 0,
    },
    body: {
        backgroundColor: 'black',
        height: '80vh',
    },
    header: {
        backgroundImage: `url(${headerPic})`,
        backgroundPosition: 'center',
        backgroundSize: 'cover',
        backgroundRepeat: 'no-repeat',
        height: '20vh',
    },
    posts: {
        backgroundColor: 'white',
    },
    cardContainer:{
        padding: theme.spacing(1),
        display: 'flex',
        justifyContent: 'center',
    },
}));

const MediumURL = "https://api.rss2json.com/v1/api.json?rss_url=https://medium.com/feed/@jhasubhash";

  
export const Blog = () => {
    const classes = useStyles();
    const [data, setData] = React.useState({profile:{}, item:[], isloading:true, error:null});

    useEffect(() => {
        if(!data.isloading) return;
        Axios.get(MediumURL).then((data) => {
          const avatar = data.data.feed.image;
          const profileLink = data.data.feed.link;
          const res = data.data.items;
          const posts = res.filter(item => item.categories.length > 0);
  
          const title = data.data.feed.title;
          console.log(data)
          setData({
            profile: {
              ptitle: title,
              profileurl: profileLink,
              avtar: avatar,
              },
              item: posts,
              isloading: false,
              error: null
          })
        })
        .catch((e) => {
          console.log(e);
        });
    });

    let post;
    if (data) {
      post = data.item.map((post, index) => (
        <Post key={index} {...post} {...data.profile} {...index} />
      ))
    }
    if (data.isloading) {
      post = <CircularProgress disableShrink />
    }

    return (
        <div className="Blog">
            <Grid container className={classes.header}></Grid>
            <Grid container className={classes.body}></Grid>
            <div className={classes.overlay}>
            <div className={classes.blog}>
                <Grid container>
                {   post}
                </Grid>
            </div>
            </div>
        </div>
    )
}