import React from "react";
import moment from "moment";
import Grid from '@material-ui/core/Grid';
import { makeStyles, withTheme } from '@material-ui/core/styles';
import Card from '@material-ui/core/Card';
import CardContent from '@material-ui/core/CardContent';
import CardMedia from '@material-ui/core/CardMedia';
import Typography from '@material-ui/core/Typography';
import Avatar from '@material-ui/core/Avatar';


const useStyles = makeStyles((theme) => ({
    r: {
        display: 'flex',
    },
    details: {
        display: 'flex',
        flexDirection: 'column',
    },
    content: {
        flex: '1 0 auto',
    },
    cover: {
        width: '100%',
    },
    cardContainer:{
        padding: theme.spacing(1),
        display: 'flex',
        justifyContent: 'center',
    },
    contentBase:{
        display:'flex',
        marginTop: '0.5rem',
        alignItems: 'center',
    },
    authorimg: {
        transform: 'translateY(50%)',
        marginLeft: '1.5625rem',
        bottom: 0,
        display: 'flex',
    },
    base: {
        marginLeft: '1.5625rem',
    },
    cLink: {
        color: 'white',
        textDecoration: 'none',
    }
}));

function ToText(node) {
    let tag = document.createElement("div");
    tag.innerHTML = node;
    node = tag.innerText;
    return node;
}

export const  Post = (props) => {
    const classes = useStyles();
 
    return (
        <Grid item xs={12} sm={6} md={3} className={classes.cardContainer}>
            <Card className={classes.r}>
                <div className={classes.details}>
                    <CardContent className={classes.content}>
                    <Typography variant="h6">
                        <a className={classes.cLink} target="_blank" href={props.link}>{props.title}</a>
                    </Typography>
                    <Typography variant="body2" color="textSecondary" >
                        {ToText(props.description.substring(0, 200))}...
                    </Typography>
                    <div className={classes.contentBase}>
                    <a
                    href={props.profileurl}
                    rel="noopener noreferrer"
                    target="_blank">
                    <Avatar alt="Subhash Jha" src={props.avtar} className={classes.profilePic} href={props.profileurl} target="_blank"/>
                    </a>
                    <Typography variant="body2"  className={classes.base}>
                            {props.author}
                    </Typography>
                    <Typography variant="body2" color="textSecondary" className={classes.base}>
                            {moment(props.pubDate).format("MMM DD, YYYY")}
                    </Typography>
                    </div>
                    </CardContent>
                </div>
                {false && <CardMedia
                    className={classes.cover}
                    image={props.thumbnail}
                    title="Live from space album cover"
                />}
            </Card>
        </Grid>
    );
}